/**
 * Template registry for the Casual Editor home page.
 *
 * Each entry maps 1:1 to a real .docx file in public/templates/
 * (generated by scripts/make-home-templates.mjs) and a PNG thumbnail
 * rendered from that .docx by scripts/make-template-thumbs.mjs.
 *
 * Add a new template:
 * 1. Add a body in make-home-templates.mjs + a writeDocx() call
 * 2. Push an entry here (id matches the .docx filename stem)
 * 3. Run `bun scripts/make-home-templates.mjs`
 * 4. Run `bun scripts/make-template-thumbs.mjs`
 * 5. Reload the editor
 */

export type TemplateCategory = 'Personal' | 'Work' | 'Education' | 'Career';

export type TemplateSource =
  /** Built in code via createEmptyDocument(); no asset fetch. */
  | { kind: 'synthesized' }
  /** Fetched from `path` (relative to the dev/prod root) on selection. */
  | { kind: 'docx'; path: string };

export interface TemplateEntry {
  id: string;
  name: string;
  description: string;
  category: TemplateCategory;
  /** Material Symbols Outlined glyph for the small icon overlay on the card. */
  icon: string;
  /** Path to the per-template thumbnail. PNG for real renders; SVG for Blank. */
  thumbnail: string;
  source: TemplateSource;
  /** File name suggested when this template lands in the editor. */
  defaultFileName: string;
  /** Featured templates appear in the Hero strip when on All + no query. */
  featured?: boolean;
}

